/* SQL ID : BbsAtclDAO.listBbsAtclAnswer 설 명 : 게시글 답글 목록 */ SELECT A.ATCL_ID , A.UP_ATCL_ID , A.BBS_ID , A.HDR_TYCD , A.SBJCT_ID , A.THMB_FILE_ID , A.ATCL_TTL , A.ATCL_CTS , A.ATCL_TAG_CD , A.ATCL_LV , A.ATCL_SEQ , A.NTCYN , A.CMNT_USEYN , A.NTC_SDTTM , A.NTC_EDTTM , A.PROC_STSCD
, A.ATHR_ID , A.EDTRYN , A.INQ_CNT , A.FVRT_USEYN , A.FVRT_CNT
, A.IMPT_ATCLYN , A.DSCSN_PROF_ID , A.RGTR_ID , A.RGTRNM , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM , B.BBS_ID FROM TB_LMS_BBS_ATCL A JOIN TB_LMS_BBS B ON A.BBS_ID = B.BBS_ID AND B.DELYN = 'N' AND B.ORG_ID = #{orgId} WHERE A.BBS_ID = #{bbsId} AND A.UP_ATCL_ID = #{parAtclId} AND A.DELYN = 'N'

