/* SQL ID : BbsAtclDAO.listDeclsBbsAtcl 설 명 : 분반 게시글 정보 목록 */ SELECT A.* FROM ( SELECT A.BBS_ID , A.ATCL_ID , A.SBJCT_ID , (SELECT SBJCTNM FROM TB_LMS_SBJCT WHERE SBJCT_ID = A.SBJCT_ID) AS SBJCTNM , (SELECT DVCLAS_NO FROM TB_LMS_SBJCT WHERE SBJCT_ID = A.SBJCT_ID) AS DVCLAS_NO FROM TB_LMS_BBS_ATCL A WHERE A.ATCL_ID IN
#{item}
) A ORDER BY (CASE WHEN A.SBJCT_ID = #{crsCreCd} THEN 0 ELSE 1 END), A.SBJCTNM, A.DVCLAS_NO

/* SQL ID : BbsAtclDAO.listRecentAtcl, TOBE: atclList 설 명 : 강의실 홈 최신글, TOBE: 게시글목록조회, 과목과관련있는 게시글목록조회로 추정 */
SELECT A.* , 'Y' IS_NEW -- CASE WHEN A.REG_DTTM > FN_DTTM_SUB(7) THEN 'Y' ELSE 'N' END AS IS_NEW , 'Y' ANSWER_YN --CASE WHEN EXISTS (SELECT 1 FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = A.ATCL_ID AND DELYN = 'N') THEN 'Y' ELSE 'N' END AS ANSWER_YN , 'Y' INQYN -- , CASE WHEN EXISTS(SELECT 1 FROM TB_LMS_BBS_ATCL_INQ_RCD WHERE ATCL_ID = A.ATCL_ID AND USER_ID = 'USR000000002') THEN 'Y' ELSE 'N' END AS INQYN , 'Y' ANS_VIEW_YN , C.DVCLAS_NO , C.SBJCTNM FROM TB_LMS_BBS_ATCL A JOIN TB_LMS_BBS B ON A.BBS_ID = B.BBS_ID AND B.DELYN = 'N' AND b.BBS_TYCD = 'NOTICE' JOIN TB_LMS_SBJCT_OFRNG C ON B.SBJCT_OFRNG_ID = C.SBJCT_OFRNG_ID
AND C.RLTN_REF_CD IN
#{item}
AND B.SBJCT_OFRNG_ID = #{crsCreCd}
WHERE 1 = 1
AND A.UP_ATCL_ID IS NULL
AND A.RGTR_ID = #{userId}
AND ( A.RGTR_ID = #{userId} )
ORDER BY A.REG_DTTM

mapper.sql:
SELECT A.* , C.ATCL_OPTN_ID , C.OPTN_CD , C.OPTN_USEYN , C.OPTN_SDTTM , C.OPTN_EDTTM , CASE WHEN A.REG_DTTM > FN_DTTM_SUB(7) THEN 'Y' ELSE 'N' END AS IS_NEW , (SELECT COUNT(1) FROM TB_LMS_BBS_ATCL_CMNT XX WHERE XX.ATCL_ID IN (SELECT ATCL_ID FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = A.ATCL_ID)) AS CMNT_CNT , FN_REF_FILE_CNT(A.ATCL_ID) AS FILE_CNT , ROW_NUMBER() OVER(ORDER BY A.REG_DTTM DESC) AS LINE_NO , COUNT(*) OVER() AS TOTAL_CNT FROM TB_LMS_BBS_ATCL A INNER JOIN TB_LMS_BBS B ON A.BBS_ID = B.BBS_ID LEFT JOIN TB_LMS_BBS_ATCL_OPTN C ON A.ATCL_ID = C.ATCL_ID WHERE 1=1 AND A.BBS_ID = #{bbsId} AND A.DELYN = 'N'
AND A.ATCL_LV = #{atclLv}
AND B.ORG_ID = #{orgId}
AND A.BBS_ID IN (
#{item}
)
AND B.SBJCT_OFRNG_ID = #{sbjctOfrngId}
AND A.REG_DTTM >= REPLACE(#{searchSdttm}, '-', '') || '000000'
AND A.REG_DTTM <= REPLACE(#{searchEdttm}, '-', '') || '235959'
AND LOWER(A.ATCL_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
AND LOWER(A.RGTRNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
AND ( LOWER(A.ATCL_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.RGTRNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
ORDER BY A.REG_DTTM DESC

SELECT A.ATCL_ID , B.ORG_ID , A.BBS_ID , A.USER_ID , A.UP_ATCL_ID , A.ATCL_TTL , A.ATCL_CTS , A.ATCL_LV , A.ATCL_SEQNO , C.ATCL_CMNT_ID , C.UP_ATCL_CMNT_ID , C.ATCL_CMNT_CTS , C.EMTICN_NO FROM TB_LMS_BBS_ATCL A JOIN TB_LMS_BBS B ON A.BBS_ID = B.BBS_ID JOIN TB_LMS_BBS_ATCL_CMNT C ON A.ATCL_ID = C.ATCL_ID WHERE 1=1 AND A.BBS_ID = #{bbsId} AND A.DELYN = 'N' AND A.ATCL_ID = #{atclId}
AND B.ORG_ID = #{orgId}
AND A.BBS_ID IN (
#{item}
)
AND B.SBJCT_OFRNG_ID = #{sbjctOfrngId}
AND LOWER(A.ATCL_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
AND LOWER(A.RGTRNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
AND ( LOWER(A.ATCL_TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.RGTRNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
ORDER BY A.REG_DTTM DESC

