/* SQL ID : BbsAtclDAO.selectBbsSbjctList 설 명 : 과목공지 목록 조회 (페이징) */
SELECT A.ATCL_ID , D.ATCL_OPTN_ID , D.OPTN_CD , D.OPTN_USEYN , D.OPTN_SDTTM , D.OPTN_EDTTM , A.BBS_ID , (SELECT ORGNM FROM TB_LMS_ORG WHERE ORG_ID = A.ORG_ID) AS ORGNM , (SELECT DEPTNM FROM TB_LMS_DEPT WHERE DEPT_ID = A.DEPT_ID) AS DEPTNM , (SELECT SBJCTNM FROM TB_LMS_SBJCT WHERE SBJCT_ID = A.SBJCT_ID) AS SBJCTNM , C.DVCLAS_NO , A.USER_ID , A.UP_ATCL_ID , A.DVCLAS_REG_ATCL_ID , A.ATCL_TTL , A.ATCL_CTS , A.ATCL_HASH_TAG_CTS , A.ATCL_LV , A.ATCL_SEQNO , A.FVRT_CNT , A.INQ_CNT , A.REF_CMNT_ID , A.THMB_FILE_ID , A.PROC_STSCD , A.HDR_TYCD , A.ATHR_ID , A.DSCSN_PROF_ID , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM , A.DELYN , A.OYN , A.RSRVYN , A.RSRV_SDTTM , A.RSRV_EDTTM , A.CMNT_PRMYN , A.NTC_GBNCD , A.AUTO_ALIM_SDTTM , A.AUTO_ALIM_EDTTM , (SELECT USERNM FROM TB_LMS_USER WHERE USER_ID = A.USER_ID) AS RGTRNM , CASE WHEN A.REG_DTTM > FN_DTTM_SUB(7) THEN 'Y' ELSE 'N' END AS IS_NEW , (SELECT COUNT(1) FROM TB_LMS_BBS_ATCL_CMNT XX WHERE XX.ATCL_ID IN (SELECT UP_ATCL_ID FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = A.ATCL_ID)) AS CMNT_CNT , ROW_NUMBER() OVER(ORDER BY A.REG_DTTM DESC) AS LINE_NO , COUNT(*) OVER() AS TOTAL_CNT , FN_REF_FILE_CNT(A.ATCL_ID) AS FILE_CNT FROM TB_LMS_BBS_ATCL A JOIN TB_LMS_BBS B ON A.BBS_ID = B.BBS_ID JOIN TB_LMS_SBJCT C ON C.SBJCT_ID = B.SBJCT_ID LEFT JOIN TB_LMS_BBS_ATCL_OPTN D ON A.ATCL_ID = D.ATCL_ID WHERE 1=1 AND A.BBS_ID = #{bbsId} AND A.ATCL_LV = #{atclLv} AND A.DELYN = 'N'
AND C.SBJCT_YR = #{sbjctYr}
AND C.SBJCT_SMSTR = #{sbjctSmstr}
AND B.ORG_ID = #{orgId}
AND C.DEPT_ID = #{deptId}
AND C.SBJCT_ID = #{sbjctId}
AND ( LOWER(A.ATCL_TTL) LIKE LOWER('%' || #{searchValue} || '%') OR LOWER(( SELECT USERNM FROM TB_LMS_USER WHERE USER_RPRS_ID = A.USER_ID )) LIKE LOWER('%' || #{searchValue} || '%') )
ORDER BY A.REG_DTTM DESC

/* SQL ID : BbsAtclDAO.selectBbsLctrQnaList 설 명 : 강의 QNA 목록 조회 (페이징) */
SELECT A.ATCL_ID , A.BBS_ID , (SELECT ORGNM FROM TB_LMS_ORG WHERE ORG_ID = A.ORG_ID) AS ORGNM , (SELECT DEPTNM FROM TB_LMS_DEPT WHERE DEPT_ID = A.DEPT_ID) AS DEPTNM , (SELECT SBJCTNM FROM TB_LMS_SBJCT WHERE SBJCT_ID = A.SBJCT_ID) AS SBJCTNM , C.DVCLAS_NO , A.USER_ID , A.UP_ATCL_ID , A.DVCLAS_REG_ATCL_ID , A.ATCL_TTL , A.ATCL_CTS , A.ATCL_HASH_TAG_CTS , A.ATCL_LV , A.ATCL_SEQNO , A.FVRT_CNT , A.INQ_CNT , A.REF_CMNT_ID , A.THMB_FILE_ID , A.PROC_STSCD , A.HDR_TYCD , A.ATHR_ID , A.DSCSN_PROF_ID , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM , A.DELYN , (SELECT USERNM FROM TB_LMS_USER WHERE USER_ID = A.USER_ID) AS RGTRNM , CASE WHEN A.REG_DTTM > FN_DTTM_SUB(7) THEN 'Y' ELSE 'N' END AS IS_NEW , (SELECT COUNT(1) FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = A.ATCL_ID) AS CMNT_CNT , (SELECT COUNT(1) FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = A.ATCL_ID AND ATCL_LV = 2) AS RSPNS_CNT , ROW_NUMBER() OVER(ORDER BY A.REG_DTTM DESC) AS LINE_NO , COUNT(*) OVER() AS TOTAL_CNT FROM TB_LMS_BBS_ATCL A JOIN TB_LMS_BBS B ON A.BBS_ID = B.BBS_ID JOIN TB_LMS_SBJCT C ON C.SBJCT_ID = B.SBJCT_ID WHERE 1=1 AND B.ORG_ID = #{orgId} AND A.BBS_ID = #{bbsId} AND A.DELYN = 'N' AND A.ATCL_LV = #{atclLv}
AND C.SBJCT_YR = #{sbjctYr}
AND C.SBJCT_SMSTR = #{sbjctSmstr}
AND B.ORG_ID = #{orgId}
AND C.DEPT_ID = #{deptId}
AND C.SBJCT_ID = #{sbjctId}
AND ( LOWER(A.ATCL_TTL) LIKE LOWER('%' || #{searchValue} || '%') OR LOWER(( SELECT USERNM FROM TB_LMS_USER WHERE USER_RPRS_ID = A.USER_ID )) LIKE LOWER('%' || #{searchValue} || '%') --> )
ORDER BY A.REG_DTTM DESC

/* SQL ID : BbsAtclDAO.selectBbsDscsnList 설 명 : 상담 목록 조회 (페이징) */
SELECT B.ORG_ID , A.ATCL_ID , A.BBS_ID , (SELECT ORGNM FROM TB_LMS_ORG WHERE ORG_ID = A.ORG_ID) AS ORGNM , (SELECT DEPTNM FROM TB_LMS_DEPT WHERE DEPT_ID = A.DEPT_ID) AS DEPTNM , (SELECT SBJCTNM FROM TB_LMS_SBJCT WHERE SBJCT_ID = A.SBJCT_ID) AS SBJCTNM , C.DVCLAS_NO , A.USER_ID , A.UP_ATCL_ID , A.DVCLAS_REG_ATCL_ID , A.ATCL_TTL , A.ATCL_CTS , A.ATCL_HASH_TAG_CTS , A.ATCL_LV , A.ATCL_SEQNO , A.FVRT_CNT , A.INQ_CNT , A.REF_CMNT_ID , A.THMB_FILE_ID , A.PROC_STSCD , A.HDR_TYCD , A.ATHR_ID , A.DSCSN_PROF_ID , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM , A.DELYN , (SELECT USERNM FROM TB_LMS_USER WHERE USER_ID = A.USER_ID) AS RGTRNM , CASE WHEN A.REG_DTTM > FN_DTTM_SUB(7) THEN 'Y' ELSE 'N' END AS IS_NEW , (SELECT COUNT(1) FROM TB_LMS_BBS_ATCL_CMNT XX WHERE XX.ATCL_ID IN (SELECT ATCL_ID FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = A.ATCL_ID)) AS CMNT_CNT , (SELECT COUNT(1) FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = A.ATCL_ID AND ATCL_LV = 2) AS RSPNS_CNT , ROW_NUMBER() OVER(ORDER BY A.REG_DTTM DESC) AS LINE_NO , COUNT(*) OVER() AS TOTAL_CNT FROM TB_LMS_BBS_ATCL A JOIN TB_LMS_BBS B ON A.BBS_ID = B.BBS_ID JOIN TB_LMS_SBJCT C ON C.SBJCT_ID = B.SBJCT_ID WHERE 1=1 AND B.ORG_ID = #{orgId} AND A.BBS_ID = #{bbsId} AND A.DELYN = 'N' AND A.ATCL_LV = #{atclLv}
AND C.SBJCT_YR = #{sbjctYr}
AND C.SBJCT_SMSTR = #{sbjctSmstr}
AND B.ORG_ID = #{orgId}
AND C.DEPT_ID = #{deptId}
