AND ( LOWER(A.ATCL_TTL) LIKE LOWER('%' || #{searchValue} || '%') OR LOWER(( SELECT USERNM FROM TB_LMS_USER WHERE USER_RPRS_ID = A.USER_ID )) LIKE LOWER('%' || #{searchValue} || '%') --> )
ORDER BY A.REG_DTTM DESC

/* SQL ID : BbsAtclDAO.selectBbsAtclGrpNtcList 설 명 : 게시판 > 과목공지 > 그룹 공지 사항 */
SELECT A.ATCL_ID , A.BBS_ID , (SELECT ORGNM FROM TB_LMS_ORG WHERE ORG_ID = A.ORG_ID) AS ORGNM , (SELECT DEPTNM FROM TB_LMS_DEPT WHERE DEPT_ID = A.DEPT_ID) AS DEPTNM , (SELECT SBJCTNM FROM TB_LMS_SBJCT WHERE SBJCT_ID = A.SBJCT_ID) AS SBJCTNM , C.DVCLAS_NO , A.USER_ID , A.UP_ATCL_ID , A.DVCLAS_REG_ATCL_ID , A.ATCL_TTL , A.ATCL_CTS , A.ATCL_HASH_TAG_CTS , A.ATCL_LV , A.ATCL_SEQNO , A.FVRT_CNT , A.INQ_CNT , A.REF_CMNT_ID , A.THMB_FILE_ID , A.PROC_STSCD , A.HDR_TYCD , A.ATHR_ID , A.DSCSN_PROF_ID , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM , A.DELYN , A.RGTRNM , CASE WHEN A.REG_DTTM > FN_DTTM_SUB(7) THEN 'Y' ELSE 'N' END AS IS_NEW , (SELECT COUNT(1) FROM TB_LMS_BBS_ATCL_CMNT XX WHERE XX.ATCL_ID IN (SELECT ATCL_ID FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = A.ATCL_ID)) AS CMNT_CNT , ROW_NUMBER() OVER(ORDER BY A.REG_DTTM DESC) AS LINE_NO , COUNT(*) OVER() AS TOTAL_CNT FROM TB_LMS_BBS_ATCL A JOIN TB_LMS_BBS B ON A.BBS_ID = B.BBS_ID JOIN TB_LMS_SBJCT C ON C.SBJCT_ID = B.SBJCT_ID WHERE 1=1 AND A.BBS_ID = #{bbsId} AND A.DELYN = 'N' AND A.ATCL_LV = #{atclLv} AND B.ORG_ID = #{orgId}
AND C.SBJCT_YR = #{sbjctYr}
AND C.SBJCT_SMSTR = #{sbjctSmstr}
AND B.ORG_ID = #{orgId}
AND C.DEPT_ID = #{deptId}
AND C.SBJCT_ID = #{sbjctId}
AND ( LOWER(A.ATCL_TTL) LIKE LOWER('%' || #{searchValue} || '%') OR LOWER(( SELECT USERNM FROM TB_LMS_USER WHERE USER_RPRS_ID = A.USER_ID )) LIKE LOWER('%' || #{searchValue} || '%') --> )
