mapper.insert:
		/*
             SQL ID : BbsAtclDAO.insertBbsAtcl
             설  명 : 게시글 정보 저장
         */
		MERGE INTO TB_LMS_BBS_ATCL A
		USING DUAL
		ON (A.ATCL_ID = #{atclId})
		WHEN MATCHED THEN
		    UPDATE SET
		          ATCL_TTL         = #{atclTtl}
		        , ATCL_CTS         = #{atclCts}
		        , ATCL_HASH_TAG_CTS = #{atclHashTagCts}
		        , THMB_FILE_ID     = #{thmbFileId}
		        , HDR_TYCD         = #{hdrTycd}
		        , MDFR_ID          = #{mdfrId}
		        , MOD_DTTM         = FN_DTTM()
		WHEN NOT MATCHED THEN
		    INSERT (
		          ATCL_ID, BBS_ID, USER_ID, UP_ATCL_ID, DVCLAS_REG_ATCL_ID
		        , ATCL_TTL, ATCL_CTS, ATCL_HASH_TAG_CTS, ATCL_LV, ATCL_SEQNO
		        , FVRT_CNT, INQ_CNT, REF_CMNT_ID, THMB_FILE_ID, PROC_STSCD
		        , HDR_TYCD, ATHR_ID, DSCSN_PROF_ID, RGTR_ID, REG_DTTM
		        , MDFR_ID, MOD_DTTM, DELYN, RGTRNM
		    ) VALUES (
		          #{atclId}
		        , #{bbsId}
		        , #{userId}
		        , #{upAtclId}
		        , #{dvclasRegAtclId}
		        , #{atclTtl}
		        , #{atclCts}
		        , #{atclHashTagCts}
		        , NVL((SELECT MAX(NVL(B.ATCL_LV, 0)) + 1 FROM TB_LMS_BBS_ATCL B WHERE B.ATCL_ID = #{upAtclId}), 0)
		        , NVL((SELECT MAX(NVL(B.ATCL_SEQNO, 0)) + 1 FROM TB_LMS_BBS_ATCL B WHERE B.BBS_ID = #{bbsId}), 1)
		        , 0
		        , 0
		        , #{refCmntId}
		        , #{thmbFileId}
		        , 'S'
		        , #{hdrTycd}
		        , #{athrId}
		        , #{dscsnProfId}
		        , #{rgtrId}
		        , FN_DTTM()
		        , #{mdfrId}
		        , FN_DTTM()
		        , 'N'
		        , #{rgtrnm}
		    )

mapper.update:
		/*
        	SQL ID : BbsAtclDAO.updateBbsAtcl
        	설  명 : 게시판게시글 수정
         */

		MERGE INTO TB_LMS_BBS_ATCL A
		USING DUAL
		   ON (A.ATCL_ID = #{atclId})
		 WHEN MATCHED THEN
		    UPDATE SET
		    	  A.ORG_ID      = #{orgId}
		    	, A.DEPT_ID     = #{deptId}
		    	, A.SBJCT_ID    = #{sbjctId}
		        , A.ATCL_TTL    = #{atclTtl}
		        , A.ATCL_CTS    = #{atclCts}
		        , A.RGTRNM      = #{rgtrnm}
		        , A.DVCLAS_NO   = #{dvclasNo}
		        , A.OYN         = #{oyn}
		        , A.NTC_GBNCD   = #{ntcGbncd}
		        , A.RSRVYN      = #{rsrvyn}
		        , A.RSRV_SDTTM  = #{rsrvSdttm}
		        , A.RSRV_EDTTM  = #{rsrvEdttm}
		        , A.CMNT_PRMYN  = #{cmntPrmyn}
		        , A.AUTO_ALIMYN  = #{autoAlimyn}
		        , A.AUTO_ALIM_SDTTM  = #{autoAlimSdttm}
		        , A.AUTO_ALIM_EDTTM  = #{autoAlimEdttm}
		        , A.MDFR_ID      = #{rgtrId}
		        , A.MOD_DTTM     = FN_DTTM()
		 WHEN NOT MATCHED THEN
		    INSERT (
		    	ORG_ID
				, DEPT_ID
				, SBJCT_ID
		        , ATCL_ID
		        , USER_ID
		        , UP_ATCL_ID
		        , BBS_ID
		        , ATCL_TTL
		        , ATCL_CTS
		        , ATCL_LV
		        , FVRT_CNT
		        , INQ_CNT
		        , PROC_STSCD
		        , RGTRNM
		        , DVCLAS_NO
		        , CMNT_PRMYN
		        , RSRVYN
		        , RSRV_SDTTM
		        , RSRV_EDTTM
		        , OYN
		        , NTC_GBNCD
		        , AUTO_ALIMYN
		        , AUTO_ALIM_SDTTM
		        , AUTO_ALIM_EDTTM
		        , RGTR_ID
		        , REG_DTTM
		    ) VALUES (
		        #{orgId}
		        , #{deptId}
		        , #{sbjctId}
		        , #{atclId}
		        , #{userId}
		        , #{upAtclId}
		        , #{bbsId}
		        , #{atclTtl}
		        , #{atclCts}
		        , 1
		        , 0
		        , 0
		        , 'S'
		        , #{rgtrnm}
		        , #{dvclasNo}
		        , #{cmntPrmyn}
		        , #{rsrvyn}
		        , #{rsrvSdttm}
		        , #{rsrvEdttm}
		        , #{oyn}
		        , #{ntcGbncd}
		        , #{autoAlimyn}
		        , #{autoAlimSdttm}
		        , #{autoAlimEdttm}
		        , #{rgtrId}
		        , FN_DTTM()
		    )

