/* SQL ID : BbsAtclDAO.listRecentBbsToday, TOBE: atclList 설 명 : 강의실 홈 최신글, TOBE: 게시글목록조회, 과목과관련있는 게시글목록조회로 추정 */ SELECT A.* , 'Y' IS_NEW -- CASE WHEN A.REG_DTTM > FN_DTTM_SUB(7) THEN 'Y' ELSE 'N' END AS IS_NEW , 'Y' ANSWER_YN --CASE WHEN EXISTS (SELECT 1 FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = A.ATCL_ID AND DELYN = 'N') THEN 'Y' ELSE 'N' END AS ANSWER_YN , 'Y' INQYN -- , CASE WHEN EXISTS(SELECT 1 FROM TB_LMS_BBS_ATCL_INQ_RCD WHERE ATCL_ID = A.ATCL_ID AND USER_ID = 'USR000000002') THEN 'Y' ELSE 'N' END AS INQYN , 'Y' ANS_VIEW_YN , C.DVCLAS_NO , C.SBJCTNM FROM TB_LMS_BBS_ATCL A JOIN TB_LMS_BBS B ON A.BBS_ID = B.BBS_ID AND B.DELYN = 'N' AND b.BBS_TYCD = 'NOTICE' JOIN TB_LMS_SBJCT_OFRNG C ON B.SBJCT_OFRNG_ID = C.SBJCT_OFRNG_ID
AND C.RLTN_REF_CD IN
#{item}
AND B.SBJCT_OFRNG_ID = #{crsCreCd}
WHERE 1 = 1
AND A.UP_ATCL_ID IS NULL
AND A.RGTR_ID = #{userId}
AND ( A.RGTR_ID = #{userId} )
ORDER BY A.REG_DTTM

		/*
             SQL ID : BbsViewDAO.bbsAtclCnt
             설  명 : 게시판 조회자 목록 수
         */
	    SELECT COUNT(*)
	      FROM TB_LMS_BBS_ATCL
	     WHERE ATCL_ID = #{atclId}
	       AND ATCL_LV = #{atclLv}

mapper.insert:
		/*
             SQL ID : BbsAtclDAO.bbsAtclRspnsRegist
             설  명 : 게시글 답변 정보 저장
         */
		INSERT INTO TB_LMS_BBS_ATCL (
	        ATCL_ID
	        , USER_ID
	        , UP_ATCL_ID
	        , BBS_ID
	        , ATCL_TTL
	        , ATCL_CTS
	        , ATCL_LV
	        , FVRT_CNT
	        , INQ_CNT
	        , PROC_STSCD
	        , RGTR_ID
	        , REG_DTTM
	    ) VALUES (
	        #{atclId}
	        , #{userId}
	        , #{upAtclId}
	        , #{bbsId}
	        , #{atclTtl}
	        , #{atclCts}
	        , 2
	        , 0
	        , 0
	        , 'S'
	        , #{userId}
	        , FN_DTTM()
	    )

mapper.update:
		/*
             SQL ID : BbsAtclDAO.bbsAtclRspnsModify
             설  명 : 게시글 답변 정보 수정
         */
	    UPDATE TB_LMS_BBS_ATCL
	       SET ATCL_TTL = #{atclTtl}
	         , ATCL_CTS = #{atclCts}
	         , MDFR_ID  = #{userId}
	         , MOD_DTTM = FN_DTTM()
	     WHERE ATCL_ID  = #{atclId}
	       AND ATCL_LV  = #{atclLv}

mapper.insert:
		/*
             SQL ID : BbsAtclDAO.bbsAtclSbjctRegist
             설  명 : 게시글 > 과목 공지 > 글쓰기 저장
         */
	    MERGE INTO TB_LMS_BBS_ATCL A
		USING DUAL
		   ON (A.ATCL_ID = #{atclId})
		 WHEN MATCHED THEN
		    UPDATE SET
		    	  A.ORG_ID      = #{orgId}
		    	, A.DEPT_ID     = #{deptId}
		    	, A.SBJCT_ID    = #{sbjctId}
		        , A.ATCL_TTL    = #{atclTtl}
		        , A.ATCL_CTS    = #{atclCts}
		        , A.RGTRNM      = #{rgtrnm}
		        , A.DVCLAS_NO   = #{dvclasNo}
		        , A.OYN         = #{oyn}
		        , A.NTC_GBNCD   = #{ntcGbncd}
		        , A.RSRVYN      = #{rsrvyn}
		        , A.RSRV_SDTTM  = #{rsrvSdttm}
		        , A.RSRV_EDTTM  = #{rsrvEdttm}
		        , A.CMNT_PRMYN  = #{cmntPrmyn}
		        , A.AUTO_ALIMYN  = #{autoAlimyn}
		        , A.AUTO_ALIM_SDTTM  = #{autoAlimSdttm}
		        , A.AUTO_ALIM_EDTTM  = #{autoAlimEdttm}
		        , A.MDFR_ID      = #{rgtrId}
		        , A.MOD_DTTM     = FN_DTTM()
		 WHEN NOT MATCHED THEN
		    INSERT (
		    	ORG_ID
				, DEPT_ID
				, SBJCT_ID
		        , ATCL_ID
		        , USER_ID
		        , UP_ATCL_ID
		        , BBS_ID
		        , ATCL_TTL
		        , ATCL_CTS
		        , ATCL_LV
		        , FVRT_CNT
		        , INQ_CNT
		        , PROC_STSCD
		        , RGTRNM
		        , DVCLAS_NO
		        , CMNT_PRMYN
		        , RSRVYN
		        , RSRV_SDTTM
		        , RSRV_EDTTM
		        , OYN
		        , NTC_GBNCD
		        , AUTO_ALIMYN
		        , AUTO_ALIM_SDTTM
		        , AUTO_ALIM_EDTTM
		        , RGTR_ID
		        , REG_DTTM
		    ) VALUES (
		        #{orgId}
		        , #{deptId}
		        , #{sbjctId}
		        , #{atclId}
		        , #{userId}
		        , #{upAtclId}
		        , #{bbsId}
		        , #{atclTtl}
		        , #{atclCts}
		        , 1
		        , 0
		        , 0
		        , 'S'
		        , #{rgtrnm}
		        , #{dvclasNo}
		        , #{cmntPrmyn}
		        , #{rsrvyn}
		        , #{rsrvSdttm}
		        , #{rsrvEdttm}
		        , #{oyn}
		        , #{ntcGbncd}
		        , #{autoAlimyn}
		        , #{autoAlimSdttm}
		        , #{autoAlimEdttm}
		        , #{rgtrId}
		        , FN_DTTM()
		    )

mapper.select:
/* SQL ID : BbsAtclDAO.selectBbsAtclRspnsList 설 명 : 과목공지 목록 조회 (페이징) */
SELECT A.ATCL_ID , D.ATCL_OPTN_ID , D.OPTN_CD , D.OPTN_USEYN , D.OPTN_SDTTM , D.OPTN_EDTTM , A.BBS_ID , (SELECT ORGNM FROM TB_LMS_ORG WHERE ORG_ID = A.ORG_ID) AS ORGNM , (SELECT DEPTNM FROM TB_LMS_DEPT WHERE DEPT_ID = A.DEPT_ID) AS DEPTNM , (SELECT SBJCTNM FROM TB_LMS_SBJCT WHERE SBJCT_ID = A.SBJCT_ID) AS SBJCTNM , C.DVCLAS_NO , A.USER_ID , A.UP_ATCL_ID , A.DVCLAS_REG_ATCL_ID , A.ATCL_TTL , A.ATCL_CTS , A.ATCL_HASH_TAG_CTS , A.ATCL_LV , A.ATCL_SEQNO , A.FVRT_CNT , A.INQ_CNT , A.REF_CMNT_ID , A.THMB_FILE_ID , A.PROC_STSCD , A.HDR_TYCD , A.ATHR_ID , A.DSCSN_PROF_ID , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM , A.DELYN , A.OYN , A.RSRVYN , A.RSRV_SDTTM , A.RSRV_EDTTM , A.CMNT_PRMYN , A.NTC_GBNCD , A.AUTO_ALIM_SDTTM , A.AUTO_ALIM_EDTTM , (SELECT USERNM FROM TB_LMS_USER WHERE USER_ID = A.USER_ID) AS RGTRNM , CASE WHEN A.REG_DTTM > FN_DTTM_SUB(7) THEN 'Y' ELSE 'N' END AS IS_NEW , (SELECT COUNT(1) FROM TB_LMS_BBS_ATCL_CMNT XX WHERE XX.ATCL_ID IN (SELECT UP_ATCL_ID FROM TB_LMS_BBS_ATCL WHERE UP_ATCL_ID = A.ATCL_ID)) AS CMNT_CNT , ROW_NUMBER() OVER(ORDER BY A.REG_DTTM DESC) AS LINE_NO , COUNT(*) OVER() AS TOTAL_CNT , FN_REF_FILE_CNT(A.ATCL_ID) AS FILE_CNT FROM TB_LMS_BBS_ATCL A JOIN TB_LMS_BBS B ON A.BBS_ID = B.BBS_ID JOIN TB_LMS_SBJCT C ON C.SBJCT_ID = B.SBJCT_ID LEFT JOIN TB_LMS_BBS_ATCL_OPTN D ON A.ATCL_ID = D.ATCL_ID WHERE 1=1 AND A.BBS_ID = #{bbsId} AND A.ATCL_LV = #{atclLv} AND A.DELYN = 'N'
AND A.ATCL_ID = #{atclId}
AND A.UP_ATCL_ID = #{upAtclId}
AND C.SBJCT_YR = #{sbjctYr}
AND C.SBJCT_SMSTR = #{sbjctSmstr}
AND B.ORG_ID = #{orgId}
AND C.DEPT_ID = #{deptId}
AND C.SBJCT_ID = #{sbjctId}
AND ( LOWER(A.ATCL_TTL) LIKE LOWER('%' || #{searchValue} || '%') OR LOWER(( SELECT USERNM FROM TB_LMS_USER WHERE USER_RPRS_ID = A.USER_ID )) LIKE LOWER('%' || #{searchValue} || '%') )
ORDER BY A.REG_DTTM DESC
